@page "/dispatch"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Filter by destination..."
           @bind="filterText" @bind:event="oninput" />
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>ETA</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">
                            @shipment.Status
                        </span>
                    </td>
                    <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (!string.IsNullOrEmpty(statusMessage))
{
    <div class="alert alert-info mt-3">@statusMessage</div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string statusMessage = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = updated.Status;
            statusMessage = $"Shipment {shipment.TrackingNumber} updated to {updated.Status}";
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize(Roles = "Customer")]
@inject IShipmentService ShipmentService
@inject Microsoft.AspNetCore.Components.Authorization.AuthenticationStateProvider AuthStateProvider

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipments</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchByTracking">Track</button>
        </div>
    </div>
</div>

@if (trackedShipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <strong>@trackedShipment.TrackingNumber</strong> — @trackedShipment.Description
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @trackedShipment.Origin</p>
                    <p><strong>To:</strong> @trackedShipment.Destination</p>
                    <p><strong>Shipped:</strong> @trackedShipment.ShippedDate.ToString("MMMM dd, yyyy")</p>
                </div>
                <div class="col-md-6">
                    <p>
                        <strong>Status:</strong>
                        <span class="badge @GetStatusBadgeClass(trackedShipment.Status)">
                            @trackedShipment.Status
                        </span>
                    </p>
                    <p><strong>Estimated Delivery:</strong> @trackedShipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</p>
                    <p><strong>Days Remaining:</strong> @DaysRemaining(trackedShipment)</p>
                </div>
            </div>
        </div>
    </div>
}
else if (searchPerformed && trackedShipment is null)
{
    <div class="alert alert-warning">No shipment found with tracking number "@trackingNumber".</div>
}

<h2 class="mt-4">My Shipments</h2>

@if (myShipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!myShipments.Any())
{
    <p>No shipments associated with your account.</p>
}
else
{
    <div class="row">
        @foreach (var shipment in myShipments)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@shipment.TrackingNumber</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@shipment.Description</h6>
                        <p class="card-text">
