        searchPerformed = true;
        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchByTracking();
    }

    private static string DaysRemaining(ShipmentDto shipment)
    {
        if (shipment.Status == ShipmentStatus.Delivered) return "Delivered";
        var days = (shipment.EstimatedDelivery - DateTime.UtcNow).Days;
        return days <= 0 ? "Due today" : $"{days} day(s)";
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}
